use Phoenix.Controller

# Define your controller
defmodule MyController do
  use MyWeb.Router.Application

  # Define an action to fetch content from a user-specified URL
  def fetch_content(conn, params) do
    # Get the target URL from request parameters
    url = params[:url]

    # Use HTTPoison to fetch the content
    response = HTTPoison.get(url)

    # Check for errors
    if response.error? do
      raise_error(:failed_to_fetch_content, url)
    else
      # Return the fetched content as JSON
      {:ok, json(response.body)}
    end
  end
end